query:
-- حذف السجلات الزائدة بشكل عشوائي للوصول إلى 425 طالب
DELETE FROM students 
WHERE id IN (
  SELECT id FROM (
    SELECT id, ROW_NUMBER() OVER (ORDER BY id) as rn
    FROM students
  ) as temp
  WHERE rn > 425
);

